// Import necessary modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const NotificationLog = require('./models/NotificationLog'); // Model for notification logs
const Task = require('./models/Task'); // Task model to retrieve scheduled tasks

/**
 * Scheduling Engine for Daily Reminder System
 * Automates task scheduling and notifications
 */

// Connect to MongoDB
mongoose.connect(process.env.MONGODB_URI, { useNewUrlParser: true, useUnifiedTopology: true })
  .then(() => console.log('MongoDB connected'))
  .catch(err => console.error('MongoDB connection error:', err));

// Schedule a task every minute for demonstration purposes
cron.schedule('* * * * *', async () => {
  try {
    const tasks = await Task.find({ status: 'active' }); // Get all active tasks
    const now = new Date();

    tasks.forEach(async (task) => {
      const taskTime = new Date();
      taskTime.setHours(task.recurrence.time.split(':')[0]);
      taskTime.setMinutes(task.recurrence.time.split(':')[1]);
      taskTime.setSeconds(0);
      // Adjust for the right day for weekly tasks
      if (task.recurrence.type === 'weekly') {
        const dayOfWeek = task.recurrence.daysOfWeek;
        if (!dayOfWeek.includes(now.getDay())) return;
      }

      if (now >= taskTime) {
        let assigneeIndex = task.rotationIndex;
        // Check unavailable members
        while (task.unavailableMembers.includes(task.assignees[assigneeIndex])) {
          assigneeIndex = (assigneeIndex + 1) % task.assignees.length; // Rotate to next member
        }

        // Notify the assignee (this could be a call to telegram or any other notification service)
        console.log(`Notifying ${task.assignees[assigneeIndex]} for task ${task.title}`);

        // Log notification success
        await NotificationLog.create({
          taskId: task.id,
          sentAt: new Date(),
          status: 'success',
          retryCount: 0
        });

        // Update rotation index to next
        task.rotationIndex = (assigneeIndex + 1) % task.assignees.length;
        await task.save(); // Save the updated task
      }
    });
  } catch (error) {
    console.error('Error in cron job:', error);
  }
});
